One thing to confirm with you: the @cognitive-fab/sam-pattern API — does createInstance() return a function you call with { initialState, component, render } that gives back named intents? The GitHub README for sam-lib shows that pattern, but if the scoped package has a different signature I'll adjust index.js accordingly.

// index.js — COSA entry point
//
// Wires together:
//   SAM instance (sam-pattern)
//   Email loop FSM (sam-fsm)
//   Application model (acceptors + initial state)
//   Next-Action Predicate (async loop driver)
//
// SAM step:
//   Action → proposes mutation
//   Acceptors → mutate model (app state + FSM pc)
//   Reactors → derive representation + fire NAP
//   NAP → launches next async action based on pc

import { createInstance, api } from '@cognitive-fab/sam-pattern'
import { emailLoopFSM } from './cosa-fsm.js'
import { initialAppState, acceptors } from './model.js'
import { nap, setIntents } from './nap.js'

// ── Create a named SAM instance ──
const COSA = createInstance({ instanceName: 'COSA' })

// ── Merge FSM initial state with app initial state ──
const initialState = {
  ...emailLoopFSM.initialState,  // injects pc: 'IDLE'
  ...initialAppState,
}

// ── Render (SAM "view") — for a server agent this is just logging ──
function render(state) {
  console.log(`[cosa] pc=${state.pc} polls=${state.pollCount}` +
    (state.lastError ? ` err=${state.lastError}` : ''))
}

// ── Wire SAM instance ──
const intents = COSA({
  initialState,
  component: {
    // FSM actions handle pc transitions; our acceptors handle data mutations
    actions:  emailLoopFSM.actions,
    acceptors: [
      ...emailLoopFSM.acceptors,   // FSM pc transitions
      ...acceptors,                // application state mutations
    ],
    reactors: [
      emailLoopFSM.stateMachine,   // FSM reactor: enforces allowed transitions
      nap,                         // NAP: drives the async chain
    ],
  },
  render,
})

// ── Inject intents into the NAP so it can fire actions ──
setIntents(intents)

// ── Boot ──
console.log('[cosa] starting — initial state: IDLE')
console.log('[cosa] poll interval:', process.env.POLL_INTERVAL_MS ?? '60000', 'ms')

// Kick off immediately on startup rather than waiting for first timer
intents.POLL()

