// cosa-fsm.js — FSM definition for the COSA email authentication loop
//
// Control states:
//   IDLE          → waiting, timer will fire POLL
//   POLLING       → fetching Gmail inbox
//   AUTHENTICATING → running 3-layer auth (thread lock + DKIM + TOTP)
//   DISPATCHING   → SSH command executing on Pi
//   REPLYING      → sending result email back to JJ
//
// The FSM enforces that no action can be called out of sequence.
// enforceAllowedActions blocks rogue or replayed actions at the SAM level.

import { fsm } from '@cognitive-fab/sam-fsm'

export const emailLoopFSM = fsm({
  pc0: 'IDLE',

  actions: {
    POLL:             ['POLLING'],
    EMAIL_RECEIVED:   ['AUTHENTICATING'],
    POLL_EMPTY:       ['IDLE'],
    AUTH_PASS:        ['DISPATCHING'],
    AUTH_FAIL:        ['IDLE'],
    DISPATCH_SUCCESS: ['REPLYING'],
    DISPATCH_FAIL:    ['REPLYING'],
    REPLY_SENT:       ['IDLE'],
  },

  states: {
    IDLE:           { transitions: ['POLL'] },
    POLLING:        { transitions: ['EMAIL_RECEIVED', 'POLL_EMPTY'] },
    AUTHENTICATING: { transitions: ['AUTH_PASS', 'AUTH_FAIL'] },
    DISPATCHING:    { transitions: ['DISPATCH_SUCCESS', 'DISPATCH_FAIL'] },
    REPLYING:       { transitions: ['REPLY_SENT'] },
  },

  deterministic: true,
  enforceAllowedActions: true,
})

// model.js — SAM acceptors and initial application state
//
// The model holds the data being processed in the current loop step.
// The FSM (cosa-fsm.js) holds the control state (pc).
// Acceptors mutate the model; they never touch control flow.

// ── Initial application state (merged with FSM's initialState in index.js) ──

export const initialAppState = {
  pendingEmail:    null,   // Gmail message object being processed
  pendingCommand:  null,   // parsed command string (post-auth)
  dispatchResult:  null,   // { output, error } from SSH
  lastError:       null,   // last error string for logging
  auditLog:        [],     // array of { ts, event, detail }
  pollCount:       0,
}

// ── Acceptors (model → proposal → void, mutate in place) ──

// Called when EMAIL_RECEIVED fires — store the inbound email
export const acceptEmail = model => proposal => {
  if (proposal.pendingEmail !== undefined) {
    model.pendingEmail = proposal.pendingEmail
    model.auditLog.push({
      ts: Date.now(),
      event: 'EMAIL_RECEIVED',
      detail: proposal.pendingEmail?.id,
    })
  }
}

// Called when AUTH_PASS fires — store the parsed command
export const acceptAuthPass = model => proposal => {
  if (proposal.pendingCommand !== undefined) {
    model.pendingCommand = proposal.pendingCommand
    model.auditLog.push({
      ts: Date.now(),
      event: 'AUTH_PASS',
      detail: proposal.pendingCommand,
    })
  }
}

// Called when AUTH_FAIL fires — clear pending email, log the rejection
export const acceptAuthFail = model => proposal => {
  if (proposal.__authFail) {
    model.auditLog.push({
      ts: Date.now(),
      event: 'AUTH_FAIL',
      detail: proposal.reason ?? 'unknown',
    })
    model.pendingEmail = null
    model.pendingCommand = null
  }
}

// Called when DISPATCH_SUCCESS or DISPATCH_FAIL fires — store result
export const acceptDispatchResult = model => proposal => {
  if (proposal.dispatchResult !== undefined) {
    model.dispatchResult = proposal.dispatchResult
    model.auditLog.push({
      ts: Date.now(),
      event: proposal.dispatchResult.error ? 'DISPATCH_FAIL' : 'DISPATCH_SUCCESS',
      detail: proposal.dispatchResult.output ?? proposal.dispatchResult.error,
    })
  }
}

// Called when REPLY_SENT fires — clear all pending state, bump poll count
export const acceptReplySent = model => proposal => {
  if (proposal.__replySent) {
    model.pendingEmail   = null
    model.pendingCommand = null
    model.dispatchResult = null
    model.lastError      = null
    model.pollCount     += 1
    model.auditLog.push({ ts: Date.now(), event: 'REPLY_SENT', detail: null })
  }
}

// Called when POLL_EMPTY fires — just bump the count
export const acceptPollEmpty = model => proposal => {
  if (proposal.__pollEmpty) {
    model.pollCount += 1
  }
}

// Called when any action sets lastError
export const acceptError = model => proposal => {
  if (proposal.lastError !== undefined) {
    model.lastError = proposal.lastError
  }
}

export const acceptors = [
  acceptEmail,
  acceptAuthPass,
  acceptAuthFail,
  acceptDispatchResult,
  acceptReplySent,
  acceptPollEmpty,
  acceptError,
]

// nap.js — Next-Action Predicate
//
// In SAM, the NAP is a reactor that fires side effects and triggers the
// next action based on the current control state. It is called synchronously
// after every model step but launches async work without blocking.
//
// The FSM's enforceAllowedActions ensures only one action fires per state.
// We use a simple "inflight" guard to prevent double-firing during async work.

import { pollUnread, sendReply, header, body } from './gmail.js'
import { authenticate } from './auth.js'
import { dispatch, listCommands } from './dispatch.js'
import { registerThread } from './store.js'
import { currentToken } from './totp.js'

const POLL_INTERVAL_MS = parseInt(process.env.POLL_INTERVAL_MS ?? '60000')
const MY_EMAIL = process.env.GMAIL_ADDRESS

let _timer    = null
let _inflight = false

// intents are injected after the SAM instance is created (see index.js)
let _intents  = null

export function setIntents(intents) {
  _intents = intents
}

// ── NAP reactor — returned to SAM as a reactor function ──

export function nap(state) {
  if (_inflight) return   // already processing
  if (!_intents)  return   // not ready yet

  switch (state.pc) {

    case 'IDLE':
      // Schedule next poll if not already scheduled
      if (!_timer) {
        _timer = setTimeout(() => {
          _timer = null
          _intents.POLL()
        }, POLL_INTERVAL_MS)
      }
      break

    case 'POLLING':
      _inflight = true
      _poll().finally(() => { _inflight = false })
      break

    case 'AUTHENTICATING':
      _inflight = true
      _authenticate(state.pendingEmail).finally(() => { _inflight = false })
      break

    case 'DISPATCHING':
      _inflight = true
      _dispatch(state.pendingCommand, state.pendingEmail).finally(() => { _inflight = false })
      break

    case 'REPLYING':
      _inflight = true
      _reply(state).finally(() => { _inflight = false })
      break
  }
}

// ── Async work functions ──

async function _poll() {
  try {
    console.log('[nap] polling Gmail...')
    const emails = await pollUnread()

    if (!emails.length) {
      console.log('[nap] inbox empty')
      _intents.POLL_EMPTY({ __pollEmpty: true })
      return
    }

    // Process one email per loop step (queue the rest for next poll)
    const email = emails[0]
    console.log('[nap] email received:', header(email, 'message-id'))
    _intents.EMAIL_RECEIVED({ pendingEmail: email })

  } catch (err) {
    console.error('[nap] poll error:', err.message)
    _intents.POLL_EMPTY({ __pollEmpty: true, lastError: err.message })
  }
}

async function _authenticate(email) {
  try {
    const result = authenticate(email)
    if (result.passed) {
      _intents.AUTH_PASS({ pendingCommand: result.command })
    } else {
      _intents.AUTH_FAIL({ __authFail: true, reason: result.reason })
    }
  } catch (err) {
    console.error('[nap] auth error:', err.message)
    _intents.AUTH_FAIL({ __authFail: true, reason: err.message })
  }
}

async function _dispatch(command, email) {
  try {
    console.log('[nap] dispatching:', command)
    const result = await dispatch(command)
    if (result.error) {
      _intents.DISPATCH_FAIL({ dispatchResult: result })
    } else {
      _intents.DISPATCH_SUCCESS({ dispatchResult: result })
    }
  } catch (err) {
    console.error('[nap] dispatch error:', err.message)
    _intents.DISPATCH_FAIL({ dispatchResult: { output: null, error: err.message } })
  }
}

async function _reply(state) {
  try {
    const email    = state.pendingEmail
    const result   = state.dispatchResult
    const threadId = email.threadId
    const msgId    = header(email, 'message-id')
    const subject  = header(email, 'subject') ?? 'COSA'
    const from     = header(email, 'from')
    const token    = currentToken()

    // Register this thread so COSA's own reply can accept future replies
    registerThread(threadId, msgId, subject)

    const outputText = result?.error
      ? `ERROR: ${result.error}${result.output ? `\n\n${result.output}` : ''}`
      : result?.output ?? '(no output)'

    const replyBody = [
      outputText,
      '',
      '---',
      `Next token valid for ~5 min. Available commands:`,
      listCommands().map(c => `  cosa: ${c} ${token}`).join('\n'),
    ].join('\n')

    await sendReply({
      threadId,
      toAddress:   from,
      fromAddress: MY_EMAIL,
      subject,
      inReplyTo:   msgId,
      text:        replyBody,
    })

    console.log('[nap] reply sent for thread:', threadId)
    _intents.REPLY_SENT({ __replySent: true })

  } catch (err) {
    console.error('[nap] reply error:', err.message)
    // Still complete the step so we don't get stuck in REPLYING
    _intents.REPLY_SENT({ __replySent: true, lastError: err.message })
  }
}


// auth.js — 3-layer email authentication pipeline
//
// Layer 1: Thread lock   — In-Reply-To must match a COSA-originated Message-ID
// Layer 2: DKIM          — Gmail authentication header must pass for gmail.com
// Layer 3: TOTP          — body must contain "cosa: <command> <6-digit-token>"
//
// Returns { passed: true, command } or { passed: false, reason }

import { header, body } from './gmail.js'
import { isKnownThread } from './store.js'
import { validateToken } from './totp.js'

const CMD_RE = /^cosa:\s+(.+?)\s+(\d{6})\s*$/im

// ── Layer 1: Thread lock ──

function checkThreadLock(message) {
  const threadId = message.threadId
  if (!isKnownThread(threadId)) {
    return { passed: false, reason: `thread ${threadId} not in registry` }
  }
  return { passed: true }
}

// ── Layer 2: DKIM ──
// Gmail exposes authentication results in the 'Authentication-Results' header.
// A legitimate gmail.com sender will have dkim=pass header.domain=gmail.com.

function checkDKIM(message) {
  const authResults = header(message, 'Authentication-Results') ?? ''
  const hasDKIM = /dkim=pass[^;]*header\.d=gmail\.com/i.test(authResults)
  if (!hasDKIM) {
    return { passed: false, reason: `DKIM fail: ${authResults.slice(0, 80)}` }
  }
  return { passed: true }
}

// ── Layer 3: TOTP passphrase ──

function checkTOTP(message) {
  const text  = body(message)
  const match = text.match(CMD_RE)
  if (!match) {
    return { passed: false, reason: 'no cosa: command found in body' }
  }
  const [, command, token] = match
  if (!validateToken(token)) {
    return { passed: false, reason: `invalid or replayed token ${token}` }
  }
  return { passed: true, command: command.trim() }
}

// ── Full pipeline ──

export function authenticate(message) {
  const t1 = checkThreadLock(message)
  if (!t1.passed) {
    console.warn('[auth] layer1 fail:', t1.reason)
    return t1
  }

  const t2 = checkDKIM(message)
  if (!t2.passed) {
    console.warn('[auth] layer2 fail:', t2.reason)
    return t2
  }

  const t3 = checkTOTP(message)
  if (!t3.passed) {
    console.warn('[auth] layer3 fail:', t3.reason)
    return t3
  }

  console.log('[auth] all layers passed, command:', t3.command)
  return { passed: true, command: t3.command }
}

// dispatch.js — SSH command execution on Pi via VPS relay
// commands.js — command registry (safe allowlist)

// ── Command registry ──
// Maps command strings → SSH commands to run on the Pi.
// Only explicitly listed commands can execute. No shell injection possible.

const COMMANDS = {
  'status':           'systemctl status baanbaan --no-pager -l',
  'restart baanbaan': 'systemctl restart baanbaan',
  'logs':             'journalctl -u baanbaan -n 50 --no-pager',
  'logs tail':        'journalctl -u baanbaan -n 100 --no-pager',
  'disk':             'df -h / /home',
  'memory':           'free -h',
  'uptime':           'uptime && cat /proc/loadavg',
  'payments status':  'systemctl status finix-relay --no-pager',
  'network':          "nmcli device status | head -20",
  'wifi':             "nmcli connection show --active",
  'db size':          'du -sh ~/baanbaan/baanbaan.db',
  'db backup':        'cp ~/baanbaan/baanbaan.db ~/backups/baanbaan-$(date +%Y%m%d-%H%M%S).db && echo done',
  'ping':             'echo pong',
}

export function resolveCommand(command) {
  const key = command.toLowerCase().trim()
  const ssh  = COMMANDS[key]
  if (!ssh) return { ok: false, error: `unknown command: "${command}"` }
  return { ok: true, ssh }
}

export function listCommands() {
  return Object.keys(COMMANDS)
}

// ── SSH execution ──

const PI_HOST = process.env.PI_SSH_HOST   // e.g. pi@192.168.1.x or via VPS tunnel
const PI_KEY  = process.env.PI_SSH_KEY    // path to private key
const TIMEOUT = parseInt(process.env.SSH_TIMEOUT_MS ?? '15000')

export async function dispatch(command) {
  const resolved = resolveCommand(command)
  if (!resolved.ok) return { output: null, error: resolved.error }

  try {
    const proc = Bun.spawn([
      'ssh',
      '-i', PI_KEY,
      '-o', 'StrictHostKeyChecking=accept-new',
      '-o', 'ConnectTimeout=10',
      '-o', 'BatchMode=yes',
      PI_HOST,
      resolved.ssh,
    ], {
      stdout: 'pipe',
      stderr: 'pipe',
    })

    const timer = setTimeout(() => proc.kill(), TIMEOUT)

    const [stdout, stderr, exitCode] = await Promise.all([
      new Response(proc.stdout).text(),
      new Response(proc.stderr).text(),
      proc.exited,
    ])

    clearTimeout(timer)

    if (exitCode !== 0) {
      return { output: stdout.trim(), error: stderr.trim() || `exit ${exitCode}` }
    }

    return { output: stdout.trim() || '(no output)', error: null }
  } catch (err) {
    return { output: null, error: err.message }
  }
}

/ gmail.js — Gmail REST API client (no SDK, Bun-native fetch)
// Uses OAuth2 refresh token stored in env.

const BASE = 'https://gmail.googleapis.com/gmail/v1/users/me'

let _accessToken   = null
let _tokenExpiry   = 0

// ── OAuth2 token refresh ──

async function accessToken() {
  if (_accessToken && Date.now() < _tokenExpiry - 60_000) return _accessToken

  const res = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      client_id:     process.env.GMAIL_CLIENT_ID,
      client_secret: process.env.GMAIL_CLIENT_SECRET,
      refresh_token: process.env.GMAIL_REFRESH_TOKEN,
      grant_type:    'refresh_token',
    }),
  })

  if (!res.ok) throw new Error(`Token refresh failed: ${res.status}`)
  const data = await res.json()
  _accessToken = data.access_token
  _tokenExpiry = Date.now() + data.expires_in * 1000
  return _accessToken
}

async function gget(path, params = {}) {
  const token = await accessToken()
  const url   = new URL(`${BASE}${path}`)
  for (const [k, v] of Object.entries(params)) url.searchParams.set(k, v)
  const res = await fetch(url, { headers: { Authorization: `Bearer ${token}` } })
  if (!res.ok) throw new Error(`Gmail GET ${path} → ${res.status}`)
  return res.json()
}

async function gpost(path, body) {
  const token = await accessToken()
  const res = await fetch(`${BASE}${path}`, {
    method:  'POST',
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body:    JSON.stringify(body),
  })
  if (!res.ok) throw new Error(`Gmail POST ${path} → ${res.status}`)
  return res.json()
}

// ── Poll unread messages ──
// Returns an array of fully-fetched message objects (with headers + body).

export async function pollUnread() {
  const list = await gget('/messages', { q: 'in:inbox is:unread', maxResults: 5 })
  if (!list.messages?.length) return []

  const messages = await Promise.all(
    list.messages.map(m => gget(`/messages/${m.id}`, { format: 'full' }))
  )

  // Mark as read so we don't re-process on next poll
  await Promise.all(messages.map(m =>
    gpost(`/messages/${m.id}/modify`, { removeLabelIds: ['UNREAD'] })
  ))

  return messages
}

// ── Parse headers ──

export function header(message, name) {
  return message.payload?.headers
    ?.find(h => h.name.toLowerCase() === name.toLowerCase())
    ?.value ?? null
}

// ── Decode body ──

export function body(message) {
  const part =
    message.payload?.parts?.find(p => p.mimeType === 'text/plain') ??
    message.payload

  const data = part?.body?.data ?? ''
  return Buffer.from(data, 'base64url').toString('utf-8')
}

// ── Build a raw RFC 2822 email ──

function buildRaw({ to, from, subject, inReplyTo, references, text }) {
  const lines = [
    `From: ${from}`,
    `To: ${to}`,
    `Subject: ${subject}`,
    inReplyTo  ? `In-Reply-To: ${inReplyTo}`  : '',
    references ? `References: ${references}`  : '',
    'Content-Type: text/plain; charset=utf-8',
    '',
    text,
  ].filter(l => l !== '')

  return Buffer.from(lines.join('\r\n')).toString('base64url')
}

// ── Send a reply in the same thread ──

export async function sendReply({ threadId, toAddress, fromAddress, subject, inReplyTo, text }) {
  const raw = buildRaw({
    to:         toAddress,
    from:       fromAddress,
    subject:    subject.startsWith('Re:') ? subject : `Re: ${subject}`,
    inReplyTo,
    references: inReplyTo,
    text,
  })

  return gpost('/messages/send', { raw, threadId })
}

// ── Create a new outbound thread (COSA → JJ) ──
// Used when COSA needs to initiate a command session.

export async function sendNew({ toAddress, fromAddress, subject, text }) {
  const raw = buildRaw({ to: toAddress, from: fromAddress, subject, text })
  return gpost('/messages/send', { raw })
}

